{
  "count": 31,
  "skills": [
    {
      "name": "ai-toolkit-trainer",
      "description": "Train custom LoRAs with ostris AI-Toolkit — covers WAN 2.2/2.1 (people, styles, video motion) and Z-Image (Turbo & Base, low-VRAM image LoRAs). Use when the user wants to train a WAN or Z-Image LoRA; covers local + RunPod setup, dataset prep, key params, and using the result in a ComfyUI workflow."
    },
    {
      "name": "anima-base",
      "description": "Anime/illustration text-to-image (ANIMA 1.0, ~2B Cosmos DiT) — use for anime, manga, illustrated characters; accepts Danbooru tags + natural language; runs/trains on <6GB VRAM; includes anime inpainting via Anima-LLLite ControlNet"
    },
    {
      "name": "anima-lora-trainer",
      "description": "Train a custom anime LoRA on the ANIMA base model — Citron's local Gradio trainer (kohya sd-scripts), <6GB VRAM, character/style LoRAs; covers setup, dataset prep, training params, and using the result in the anima-base workflow"
    },
    {
      "name": "civitai",
      "description": "Pair the official Civitai MCP (https://mcp.civitai.com/mcp) with comfyui-mcp to discover models on Civitai and install/generate them locally. Use when the user wants to find a checkpoint/LoRA/embedding on Civitai, browse Civitai images for inspiration, or download a Civitai model into their ComfyUI. comfyui-mcp does NOT proxy Civitai — it hands version ids to the local download/wire/generate loop."
    },
    {
      "name": "color-correction",
      "description": "Diagnose and fix video/image color OBJECTIVELY with the analyze_color tool (scopes/stats — black/white points, contrast, saturation, clipping, cast) instead of eyeballing a contact sheet. Covers the \"washed out\" signature, why reference color-match (mkl/ColorMatch/ColorMatchAdobe) CAN'T add contrast a flat source lacks, the levels/contrast-stretch fix (core AdjustContrast / CurveEditor), the measure→fix→re-measure loop, the side-by-side sandbox pattern, and where to place the fix in a render graph (after decode, before save). Use when a render looks washed out / flat / dull / over-saturated / color-cast, or when deciding between a color-match and a contrast/levels fix."
    },
    {
      "name": "comfyui-core",
      "description": "Core ComfyUI knowledge — workflow format, node types, pipeline patterns, and MCP tool usage"
    },
    {
      "name": "comfyui-frontend-extensions",
      "description": "Authoring ComfyUI v2 frontend extensions with @comfyorg/extension-api — defineNode/defineExtension/defineWidget, shell UI (sidebar tabs, commands, hotkeys), typed events, and handles. Use when writing or editing ComfyUI web-UI extension code (custom node JS, sidebar panels, widgets)."
    },
    {
      "name": "comfyui-node-registry",
      "description": "Authoring & publishing ComfyUI custom nodes to the Comfy Registry — node structure, pyproject.toml spec, comfy-cli publishing, and CI"
    },
    {
      "name": "debug-render",
      "description": "Debug a WRONG or imperfect render (not a hard error) by inspecting inputs and intermediate steps with run-to-node — render one branch up to an output, preview-tap latents/masks/preprocessor maps, localize the first bad stage, then fix. Use when a final image/video comes out wrong — artifacts, wrong subject/pose/composition/color, blur, a ControlNet/IPAdapter/mask/LoRA not taking, a two-stage refiner or upscale degrading the result — rather than the run failing with an error (for errors/OOM/missing nodes use the troubleshooting skill)."
    },
    {
      "name": "director",
      "description": "Full production pipeline — story to scenes, Z-Image start frames, Qwen Edit end frames, WAN FLF video clips, ffmpeg concatenation"
    },
    {
      "name": "ernie-image",
      "description": "Build Baidu ERNIE-Image / ERNIE-Image-Turbo workflows — primarily TEXT-TO-IMAGE. Pick ERNIE when you need precise multilingual text rendering, posters/signage, manga/anime multi-panel layouts, or strong instruction following for complex multi-object scenes. Also supports denoise-based image-to-image refine (NOT instruction-grounded editing — use Qwen-Image-Edit or Flux Kontext for \"change X in this photo\" edits)."
    },
    {
      "name": "flux-txt2img",
      "description": "Build Flux txt2img workflows — Flux.1 Dev (SRPO), Flux 2 Klein 9B, Turbo LoRAs, FluxGuidance, and DualCLIPLoader patterns"
    },
    {
      "name": "ideogram-ultra",
      "description": "Build Ideogram 4 (Ideogram Ultra) txt2img and img2img workflows — local open-weights model, dual conditional/unconditional models with DualModelGuider, Qwen3-VL text encoder, and structured JSON (\"compositional deconstruction\") prompts for strong text rendering and layout control"
    },
    {
      "name": "installer-packs",
      "description": "Use when installing a model family from an installer pack, or when building/deriving a new pack from an upstream installer or a workflow JSON. Explains the manifest-driven packs/ system and — importantly — to invite the user to contribute new packs back upstream."
    },
    {
      "name": "krea2-txt2img",
      "description": "Build Krea 2 Turbo txt2img workflows — native krea2 CLIPLoader, Qwen3-VL encoder, Qwen image VAE, 8-step turbo settings, and Ideogram-style JSON prompting"
    },
    {
      "name": "ltxv2-video",
      "description": "Build Lightricks LTX-2 / LTX-2.3 video workflows — text-to-video, image-to-video, GGUF and bundled checkpoints, distilled model, camera control LoRAs, synchronized audio, two-stage upscaling, and swapping alternate/GGUF base models"
    },
    {
      "name": "model-compatibility",
      "description": "Model family compatibility matrix — loaders, resolutions, samplers, CFG, VAE, ControlNet, and LoRA compatibility for SD 1.5, SDXL, Flux, SD3, and video models"
    },
    {
      "name": "model-registry",
      "description": "Curated download URLs and target directories for every model the comfyui-mcp skills reference — checkpoints, VAEs, text encoders, LoRAs — organized by family (Flux, WAN, LTX, Qwen, Z-Image, SD15/SDXL). Use when downloading models with download_model / download_civitai_model, when a workflow fails with a missing-model error, or when setting up a new machine."
    },
    {
      "name": "prompt-engineering",
      "description": "ComfyUI prompt engineering knowledge — CLIP text encoding syntax, weight modifiers, model-specific prompting strategies, and best practices"
    },
    {
      "name": "qwen-image-edit",
      "description": "Build Qwen Image Edit workflows — model loading, conditioning, LoRAs, prompt patterns, and XY plot testing"
    },
    {
      "name": "qwen-txt2img",
      "description": "Build Qwen Image 2512 text-to-image workflows — QwenImageIntegratedKSampler, separate component loading, lightning LoRAs, and fine-tuned model variants"
    },
    {
      "name": "report-bug",
      "description": ""
    },
    {
      "name": "triton-sageattention",
      "description": ""
    },
    {
      "name": "troubleshooting",
      "description": "Common ComfyUI errors and fixes — OOM, missing nodes, dtype mismatches, black images, and debugging strategies"
    },
    {
      "name": "video-extend",
      "description": "Extend / continue a video temporally with Pusa 2.2 in ComfyUI — temporal flowmatching (the flowmatch_pusa scheduler + WanVideoAddPusaNoise) on the WanVideoWrapper stack with WAN 2.2 T2V A14B (HIGH/LOW) models and the Pusa V1 LoRAs, conditioning on the loaded clip via WanVideoEncode so the existing motion carries into the continuation. Covers the kijai wanvideo_2_2_14B_Pusa_extension graph, model/LoRA slots + downloads, noise/length/scheduler settings, chaining multiple extensions, VRAM tiers, gotchas, and the extend→upscale handoff."
    },
    {
      "name": "video-upscale",
      "description": "Upscale and restore video in ComfyUI — both the quick local path (per-frame ESRGAN like 4x_foolhardy_Remacri via ImageUpscaleWithModel + 4x→2x supersample, with its temporal-flicker tradeoff) and temporal-aware super-resolution (SeedVR2, the newer FlashVSR) with the downscale-first restore pipeline; RIFE/FILM frame interpolation via the BUILT-IN ComfyUI 0.26 FrameInterpolate (rife_v4.26 in models/frame_interpolation/) or the ComfyUI-Frame-Interpolation pack; 2x/4x scaling, VRAM tiers, VHS encode. Captures the classic downscale→SeedVR2→RIFE recipe and the current 2026 recommendation."
    },
    {
      "name": "wan-flf-video",
      "description": "Build WAN 2.2 First-Last-Frame video workflows — native dual hi-lo (required), and WanVideoWrapper VACE approaches"
    },
    {
      "name": "wan-multitalk",
      "description": "Build WAN MultiTalk audio-driven talking-avatar / lip-sync video workflows — MeiGen-AI MultiTalk on WAN 2.1 14B I2V via kijai WanVideoWrapper (portrait + audio → lip-synced video)"
    },
    {
      "name": "wan-t2v-video",
      "description": "Build WAN 2.2 Text-to-Video workflows — dual hi-lo models, lightning LoRAs, VACE modules, and KSamplerAdvanced two-pass"
    },
    {
      "name": "workflow-layout",
      "description": "Lay out and organize a ComfyUI workflow cleanly on the live panel canvas — dependency-layered node placement with no overlaps, subgraphs, colored group boxes, and subgraph rail alignment. Use when asked to tidy / clean up / organize / arrange a workflow, add groups or subgraphs, fix overlapping nodes, or build a workflow that should look good from the start."
    },
    {
      "name": "z-image-txt2img",
      "description": "Build Z-Image txt2img workflows — RedCraft checkpoint, Z-Image Turbo/Base LoRAs, ControlNet, and sampler presets"
    }
  ]
}

